INSERT INTO reviews (booking_id, rating, comment, host_response, response_date, created_at) VALUES
(1, 5, 'Отличная квартира! Чисто, уютно, отличное расположение. Хозяин очень отзывчивый.', 'Спасибо за отзыв! Рады, что вам понравилось. Ждем снова!', '2024-02-06 12:00:00', '2024-02-05 18:00:00'),
(2, 4, 'Прекрасный дом у озера. Всё понравилось, только дорога немного разбита.', 'Спасибо за отзыв! Работаем над дорогой.', '2024-02-16 10:30:00', '2024-02-15 20:00:00'),
(3, 5, 'Вид на море - это нечто! Апартаменты шикарные, вернемся обязательно.', NULL, NULL, '2024-02-13 15:00:00'),
(4, 4, 'Хорошая квартира, всё есть для комфортного проживания. Метро рядом.', 'Спасибо! Ждем вас снова.', '2024-02-26 11:00:00', '2024-02-25 19:00:00'),
(5, 5, 'Студия просто супер! Современный ремонт, умный дом - очень удобно.', NULL, NULL, '2024-02-19 14:00:00');
